export interface Customer {
  yearsWithMHPCO: number;
}

export interface Item {
  type: string;
  material?: string;
  enchantment?: number;
  cursed?: boolean;
}

export interface QuoteInput {
  customer: Customer;
  items: Item[];
}

const PROCESSING_FEE = 5;

const NO_BASE_PREMIUM = 0;

const BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
};

const basePremiumFor = (item: Item): number =>
  BASE_PREMIUMS[item.type] ?? NO_BASE_PREMIUM;

export const quote = (input: QuoteInput): number => {
  const base = input.items.reduce((sum, item) => sum + basePremiumFor(item), 0);
  return base + PROCESSING_FEE;
};

export const claim = (...args: unknown[]): unknown => {
  return undefined; // Not yet implemented
};

import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

