    expect(
      quote({
        customer: { yearsWithMHPCO: 0 },
        items: [{ type: "sword", material: "steel", enchantment: 3, cursed: false }],
      })
    ).toBe(105);
  });
  it("quote: single amulet → premium 65 G (60 base + 5 fee)", () => {
    expect(
      quote({ customer: { yearsWithMHPCO: 0 }, items: [{ type: "amulet" }] })
    ).toBe(65);
  });
  it("quote: single staff → premium 85 G (80 base + 5 fee)", () => {
    expect(
      quote({ customer: { yearsWithMHPCO: 0 }, items: [{ type: "staff" }] })
    ).toBe(85);
  });
  it.todo("quote: single potion → premium 45 G (40 base + 5 fee)");

  // --- Quote: components and building blocks ---
  it.todo("quote: 2 runes → base 50 G → premium 55 G");
  it.todo("quote: 3 runes → base 60 G (block applies) → premium 65 G");
  it.todo("quote: 4 runes → base 100 G (no block, exactly 3 required) → premium 105 G");
